
INSERT INTO public.theme_category_briefs
(vertical, subcategory, display_name, prompt_addendum, palette_hints, vocabulary, hero_archetypes, section_priority, image_style, sort_order)
VALUES
-- Healthcare
('services','doctor-clinic','Doctor / Clinic','Independent doctor or small clinic. Emphasise trust, qualifications, consultation hours, and a prominent Book Appointment CTA. Hero should feel calm and clinical, not promotional. Show specialisations, fees, and a clean schedule view.','medical white, trust blue, soft teal, sage','Consultation, OPD, appointment, MBBS, specialisation, patient, prescription, follow-up, family doctor, second opinion','clinic-portrait, doctor-with-stethoscope, calm-waiting-room','{announcement_bar,hero,usp_strip,image_with_text,testimonials,contact_form,newsletter}','clean clinical photography, soft natural light, calm tones',200),
('services','nursing-home','Nursing Home / Multi-Speciality','Multi-doctor nursing home with departments (cardiology, ortho, paediatrics, etc.). Hero must convey 24x7 availability, emergency line, and easy appointment booking. Show department grid, doctor team, in-patient facilities and insurance partners.','hospital white, deep navy trust, emerald accent','Department, in-patient, OPD, ICU, emergency, specialist, on-call, admission, diagnostic','hospital-facade, doctor-team, modern-ward','{announcement_bar,hero,category_grid,usp_strip,image_with_text,testimonials,contact_form,newsletter}','documentary hospital photography, bright corridors, warm humans',201),
('services','dental-clinic','Dental Clinic','Cosmetic and family dentistry. Hero should be bright, confident, and smile-led. Highlight services (whitening, aligners, root canal), pricing transparency, EMI options, and appointment booking.','pearl white, mint, soft coral, charcoal','Smile, aligners, whitening, root canal, scaling, implant, paediatric dentistry, cosmetic','smiling-patient, modern-chair, before-after-smile','{announcement_bar,hero,usp_strip,image_with_text,featured_products,testimonials,newsletter}','crisp dental photography, white backgrounds, confident smiles',202),
('services','physio-rehab','Physiotherapy & Rehab','Physiotherapist or rehab studio offering at-clinic and home-visit sessions. Hero should feel energetic and recovery-focused. Show conditions treated, session packages, and home-visit toggle.','calming sage, soft orange, slate, off-white','Recovery, mobility, pain relief, sports injury, post-surgery, home visit, session package','therapist-with-patient, rehab-equipment, motion-stretch','{announcement_bar,hero,usp_strip,image_with_text,testimonials,featured_products,newsletter}','warm rehab studio photography, motion-blur action shots',203),
('services','ayurveda-clinic','Ayurveda & Wellness Clinic','Authentic Ayurveda clinic / Panchakarma centre. Hero should feel grounded, traditional, premium-wellness. Show therapies, doctor lineage, treatment packages, retreat options.','sandalwood, sage green, ochre, terracotta','Dosha, Panchakarma, abhyanga, vaidya, herbal, classical, retreat, consultation','traditional-therapy, herbs-flatlay, vaidya-portrait','{announcement_bar,hero,image_with_text,usp_strip,featured_products,testimonials,newsletter}','warm earthy photography, brass + herbs, candlelit treatment rooms',204),
('services','veterinary-clinic','Veterinary Clinic','Pet doctor / animal hospital. Hero must feel warm, friendly, pet-positive. Show services (vaccination, grooming, surgery), home-visit option, and emergency line.','warm cream, friendly teal, paw-print orange','Vaccination, deworming, grooming, neuter, home visit, pet wellness, vet on call','vet-with-pet, happy-dog, exam-room','{announcement_bar,hero,usp_strip,image_with_text,testimonials,featured_products,newsletter}','candid pet photography, soft natural light, joyful expressions',205),
('services','diagnostic-lab','Diagnostic Lab / Imaging','Pathology lab or imaging centre with home sample collection. Hero must communicate speed, accuracy, and home-collection booking. Show test packages, lab certifications, sample-pickup toggle.','clinical white, electric blue, lime accent','Home collection, NABL, report, full body checkup, blood test, scan, package','lab-technician, sample-vials, modern-equipment','{announcement_bar,hero,featured_products,usp_strip,image_with_text,testimonials,newsletter}','clean lab photography, blue-lit equipment, precise compositions',206),

